  }\n\n  function getFilteredData(loaiPin) {\n    var filtered = allData.filter(function(r) {\n      return r.Loai_pin === loaiPin;\n    });\n    filtered.sort(function(a, b) {\n      if (a.KV < b.KV) return -1;\n      if (a.KV > b.KV) return 1;\n      return a.ma_moi < b.ma_moi ? -1 : 1;\n    });\n    var kvMap = {};\n    filtered.forEach(function(r) {\n      if (!kvMap[r.KV]) kvMap[r.KV] = 0;\n      kvMap[r.KV]++;\n    });\n    return {\n      cats      : filtered.map(function(r) { return r.ma_moi; }),\n      vals      : filtered.map(function(r) { return r.du_pin_saucap; }),\n      kv_groups : { KV: Object.keys(kvMap), n_cols: Object.values(kvMap) },\n      n_total   : filtered.length\n    };\n  }\n\n  function drawKVLabels(chart, groups, N, el) {\n    var pLeft   = chart.plotLeft;\n    var pRight  = chart.chartWidth - pLeft - chart.plotWidth;\n    var colW    = chart.plotWidth / N;\n    var nGroups = groups.KV.length;\n    var pullUp  = chart.marginBottom - 25;\n\n    el.style.position = 'relative';\n    el.querySelectorAll('._kv_sep, ._kv_row').forEach(function(o) {\n      o.parentNode.removeChild(o);\n    });\n\n    // Đường nét đứt phân chia KV\n    var cumCols = 0;\n    for (var i = 0; i < nGroups - 1; i++) {\n      cumCols += groups.n_cols[i];\n      var sep = document.createElement('div');\n      sep.className = '_kv_sep';\n      sep.style.cssText = [\n        'position:absolute',\n        'left:' + Math.round(pLeft + cumCols * colW) + 'px',\n        'top:' + chart.plotTop + 'px',\n        'width:1px',\n        'height:' + (chart.plotHeight + 18) + 'px',\n        'border-left:1px dashed #999999',\n        'pointer-events:none',\n        'z-index:3'\n      ].join(';');\n      el.appendChild(sep);\n    }\n\n    // Label tên KV bên dưới\n    var row = document.createElement('div');\n    row.className = '_kv_row';\n    row.style.cssText = [\n      'display:flex',\n      'margin-top:-' + pullUp + 'px',\n      'padding-left:' + pLeft + 'px',\n      'padding-right